#!/usr/bin/env python3
"""Generate the Results and Evaluation evidence-flow figure."""

from __future__ import annotations

from pathlib import Path
from textwrap import dedent


ROOT = Path(__file__).resolve().parents[1]
DEFAULT_TIKZ = ROOT / "paper" / "figures" / "evaluation_evidence_flow.tex"
DEFAULT_PNG = ROOT / "output" / "pdf" / "figures" / "evaluation_evidence_flow.png"


def write_tikz(path: Path = DEFAULT_TIKZ) -> Path:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(
        dedent(
            r"""
            % Generated by scripts/render_evaluation_figure.py; do not edit by hand.
            \resizebox{\linewidth}{!}{%
            \begin{tikzpicture}[font=\scriptsize, line width=0.45pt]
            \tikzstyle{evidence}=[draw=blue!65!black, fill=blue!7, rounded corners=2pt, align=center, text width=2.25cm, minimum height=0.62cm]
            \tikzstyle{gate}=[draw=orange!80!black, fill=orange!10, rounded corners=2pt, align=center, text width=2.25cm, minimum height=0.62cm]
            \tikzstyle{claim}=[draw=green!55!black, fill=green!9, rounded corners=2pt, align=center, text width=2.25cm, minimum height=0.62cm]
            \tikzstyle{warn}=[draw=orange!80!black, fill=orange!10, rounded corners=2pt, align=center, text width=2.25cm, minimum height=0.62cm]
            \tikzstyle{arrow}=[->, draw=black!65, line width=0.55pt]

            \node[font=\scriptsize\bfseries, text=blue!60!black] at (0, 2.7) {Generated evidence};
            \node[font=\scriptsize\bfseries, text=orange!80!black] at (3.35, 2.7) {Trust gates};
            \node[font=\scriptsize\bfseries, text=green!45!black] at (6.75, 2.7) {Reported claims};

            \node[evidence] (hdl) at (0, 1.85) {Directed HDL\\matrix};
            \node[evidence] (compare) at (0, 1.15) {Comparison\\CSVs};
            \node[evidence] (stress) at (0, 0.45) {Fuzz and\\sweep};
            \node[evidence] (yosys) at (0, -0.25) {Yosys\\proxy};

            \node[gate] (validator) at (3.35, 1.85) {Validator +\\reference};
            \node[gate] (papercheck) at (3.35, 1.15) {Paper-number\\check};
            \node[gate] (safety) at (3.35, 0.45) {Safety +\\sensitivity};
            \node[gate] (costcheck) at (3.35, -0.25) {Cost\\qualifier};

            \node[claim] (cycles) at (6.75, 1.85) {7.59\% cycles\\5.78\% energy};
            \node[warn] (oracle) at (6.75, 1.15) {-8.90\%\\oracle gap};
            \node[claim] (safetyclaim) at (6.75, 0.45) {0 faults\\2,106 sweep rows};
            \node[warn] (area) at (6.75, -0.25) {165.03\%\\area delta};

            \draw[arrow] (hdl.east) -- (validator.west);
            \draw[arrow] (compare.east) -- (papercheck.west);
            \draw[arrow] (stress.east) -- (safety.west);
            \draw[arrow] (yosys.east) -- (costcheck.west);

            \draw[arrow] (validator.east) -- (cycles.west);
            \draw[arrow] (papercheck.east) -- (oracle.west);
            \draw[arrow] (safety.east) -- (safetyclaim.west);
            \draw[arrow] (costcheck.east) -- (area.west);

            \node[align=center, font=\scriptsize, text=black!65] at (3.35, -1.02)
              {Claims are accepted only after generated outputs pass reproducibility checks.};
            \end{tikzpicture}%
            }
            """
        ).lstrip(),
        encoding="utf-8",
    )
    return path


def _font(size: int, bold: bool = False):
    from PIL import ImageFont

    candidates = [
        "arialbd.ttf" if bold else "arial.ttf",
        "calibrib.ttf" if bold else "calibri.ttf",
        "segoeuib.ttf" if bold else "segoeui.ttf",
    ]
    for candidate in candidates:
        try:
            return ImageFont.truetype(candidate, size)
        except OSError:
            continue
    return ImageFont.load_default()


def _centered_text(draw, box, text: str, font, fill: str) -> None:
    left, top, right, bottom = box
    lines = text.split("\n")
    line_boxes = [draw.textbbox((0, 0), line, font=font) for line in lines]
    line_heights = [b[3] - b[1] for b in line_boxes]
    total_height = sum(line_heights) + 8 * (len(lines) - 1)
    y = top + ((bottom - top) - total_height) / 2
    for line, bounds, height in zip(lines, line_boxes, line_heights):
        width = bounds[2] - bounds[0]
        x = left + ((right - left) - width) / 2
        draw.text((x, y), line, font=font, fill=fill)
        y += height + 8


def _arrow(draw, start: tuple[int, int], end: tuple[int, int], color: str = "#475569") -> None:
    sx, sy = start
    ex, ey = end
    draw.line((sx, sy, ex - 16, ey), fill=color, width=5)
    draw.polygon([(ex, ey), (ex - 18, ey - 10), (ex - 18, ey + 10)], fill=color)


def render_png(path: Path = DEFAULT_PNG) -> Path:
    from PIL import Image, ImageDraw

    path.parent.mkdir(parents=True, exist_ok=True)
    width, height = 1800, 880
    image = Image.new("RGB", (width, height), "#ffffff")
    draw = ImageDraw.Draw(image)

    title_font = _font(46, bold=True)
    heading_font = _font(30, bold=True)
    body_font = _font(28)
    small_font = _font(24)

    draw.text((62, 42), "PipeSense Results Evidence Flow", font=title_font, fill="#111827")
    draw.text((64, 100), "Generated outputs must pass trust checks before they become paper claims.", font=small_font, fill="#475569")

    columns = [
        ("Generated evidence", 90, "#dbeafe", "#2563eb", "#1e3a8a"),
        ("Trust gates", 650, "#ffedd5", "#f97316", "#7c2d12"),
        ("Reported claims", 1210, "#dcfce7", "#16a34a", "#14532d"),
    ]
    for label, x, fill, stroke, text_color in columns:
        draw.rounded_rectangle((x, 172, x + 500, 742), radius=26, fill=fill, outline=stroke, width=5)
        draw.text((x + 36, 204), label, font=heading_font, fill=text_color)

    evidence = [
        ("Directed HDL matrix", "78 benchmark/mode rows"),
        ("Comparison CSVs", "static + oracle baselines"),
        ("Fuzz and sweep", "500 seeds, 27 configs"),
        ("Yosys area proxy", "generic-cell cost"),
    ]
    gates = [
        ("Validator + reference", "timeouts, safety, state hash"),
        ("Paper-number check", "tables match CSVs"),
        ("Safety + sensitivity", "no faults, non-wins shown"),
        ("Cost qualifier", "proxy, not calibrated"),
    ]
    claims = [
        ("7.59% cycles, 5.78% energy", "vs. static normal"),
        ("-8.90% oracle gap", "bounded, not optimal"),
        ("0 faults, 2,106 sweep rows", "safety + sensitivity"),
        ("165.03% area delta", "generic-cell proxy"),
    ]

    def draw_cards(items, x, stroke, fill):
        ys = [286, 394, 502, 610]
        centers = []
        for (main, sub), y in zip(items, ys):
            box = (x + 46, y, x + 454, y + 74)
            draw.rounded_rectangle(box, radius=16, fill="#ffffff", outline=stroke, width=4)
            _centered_text(draw, (box[0], box[1] + 6, box[2], box[1] + 38), main, body_font, "#111827")
            _centered_text(draw, (box[0], box[1] + 40, box[2], box[3] - 4), sub, small_font, "#475569")
            centers.append((box[2], (box[1] + box[3]) // 2))
        return centers

    left = draw_cards(evidence, 90, "#2563eb", "#dbeafe")
    middle = draw_cards(gates, 650, "#f97316", "#ffedd5")
    right = draw_cards(claims, 1210, "#16a34a", "#dcfce7")

    for source, target in zip(left, middle):
        _arrow(draw, (source[0] + 28, source[1]), (target[0] - 408, target[1]))
    for source, target in zip(middle, right):
        _arrow(draw, (source[0] + 28, source[1]), (target[0] - 408, target[1]))

    draw.rounded_rectangle((450, 786, 1350, 838), radius=18, fill="#f8fafc", outline="#cbd5e1", width=3)
    _centered_text(
        draw,
        (450, 786, 1350, 838),
        "Reviewer-trust rule: no generated evidence, no claim.",
        small_font,
        "#334155",
    )

    image.save(path)
    return path


def main() -> int:
    tikz = write_tikz()
    png = render_png()
    print(f"Wrote {tikz}")
    print(f"Wrote {png}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
